// Guard: if config not loaded yet, drop message silently
const _config = flow.get('config');
const _appUrl = _config ? _config.appScriptUrl : '';

let gridLost = 0;

if (typeof msg.payload === "object") {
    if (msg.payload.value !== undefined) {
        gridLost = Number(msg.payload.value);
    } else if (msg.payload.statusCode !== undefined) {
        gridLost = Number(msg.payload.statusCode);
    } else {
        return null;
    }
} else {
    gridLost = Number(msg.payload);
}

// ── State in flow context — survives re-deploys (node context does not) ─────
const glState   = flow.get('gridLostState') || {};
let previous    = glState.previous;    // undefined on first boot / first deploy
let outageStart = glState.outageStart; // epoch ms, null when grid is up

function gridLabel(value) {
    if (value === 0) return "OK";
    if (value === 1) return "WARNING";
    if (value === 2) return "ALARM";
    return "UNKNOWN_" + value;
}

node.status({
    fill:  gridLost === 0 ? "green" : "red",
    shape: "dot",
    text:  "GridLost: " + gridLabel(gridLost)
});

// Atomic save helper — always writes both fields together
function saveState(prev, start) {
    flow.set('gridLostState', { previous: prev, outageStart: start });
}

// ── First message after boot or re-deploy ────────────────────────────────────
if (previous === undefined) {
    saveState(gridLost, null);

    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:            "GridLost",
        site:             _config ? _config.site : "",
        timestamp:        new Date().toISOString(),
        source:           "GRID_LOST",
        event:            "INITIAL_STATE",
        previous_state:   "",
        new_state:        gridLabel(gridLost),
        duration_minutes: "",
        grid_lost_status: gridLost
    };

    msg.url = _appUrl;
    if (!_appUrl) { return null; }
    return msg;
}

// ── Grid just went down ───────────────────────────────────────────────────────
if (previous === 0 && gridLost >= 1) {
    const start = Date.now();
    saveState(gridLost, start);

    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:            "GridLost",
        site:             _config ? _config.site : "",
        timestamp:        new Date(start).toISOString(),
        source:           "GRID_LOST",
        event:            "GRID_LOST_STARTED",
        previous_state:   gridLabel(previous),
        new_state:        gridLabel(gridLost),
        duration_minutes: "",
        grid_lost_status: gridLost
    };

    msg.url = _appUrl;
    if (!_appUrl) { return null; }
    return msg;
}

// ── Grid just restored ────────────────────────────────────────────────────────
if (previous >= 1 && gridLost === 0) {
    const end             = Date.now();
    const durationMs      = outageStart ? end - outageStart : 0;
    const durationMinutes = Math.round(durationMs / 60000);

    const daily = flow.get("outageDaily") || { count: 0, minutes: 0 };
    daily.count   += 1;
    daily.minutes += durationMinutes;
    flow.set("outageDaily", daily);

    saveState(gridLost, null);

    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:            "GridLost",
        site:             _config ? _config.site : "",
        timestamp:        new Date(end).toISOString(),
        source:           "GRID_LOST",
        event:            "GRID_RESTORED",
        previous_state:   gridLabel(previous),
        new_state:        gridLabel(gridLost),
        duration_minutes: durationMinutes,
        grid_lost_status: gridLost
    };

    msg.url = _appUrl;
    if (!_appUrl) { return null; }
    return msg;
}

// ── No transition — just persist current state ────────────────────────────────
saveState(gridLost, outageStart);
return null;

// Guard: if config not loaded yet, drop message silently
const _config = flow.get('config');
const _appUrl = _config ? _config.appScriptUrl : '';

let state;

if (typeof msg.payload === "object" && msg.payload.value !== undefined) {
    state = Number(msg.payload.value);
} else {
    state = Number(msg.payload);
}

// ── State in flow context — survives re-deploys (node context does not) ─────
const acState  = flow.get('acInputState') || {};
let previous   = acState.previous;   // undefined on first boot / first deploy
let stateStart = acState.stateStart; // epoch ms of when current state began

function label(value) {
    if (value === 0)   return "NOT_AVAILABLE";
    if (value === 1)   return "GRID";
    if (value === 2)   return "GENERATOR";
    if (value === 3)   return "SHORE";
    if (value === 240) return "INVERTING";
    return "UNKNOWN_" + value;
}

node.status({
    fill:  "green",
    shape: "dot",
    text:  "Current: " + label(state)
});

// Atomic save helper
function saveState(prev, start) {
    flow.set('acInputState', { previous: prev, stateStart: start });
}

// ── First message after boot or re-deploy ────────────────────────────────────
if (previous === undefined) {
    saveState(state, Date.now());

    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:            "ACInput",
        site:             _config ? _config.site : "",
        timestamp:        new Date().toISOString(),
        source:           "AC_INPUT",
        event:            "INITIAL_STATE",
        previous_state:   "",
        new_state:        label(state),
        duration_minutes: "",
        grid_lost_status: ""
    };

    msg.url = _appUrl;
    if (!_appUrl) { return null; }
    return msg;
}

// ── State changed ─────────────────────────────────────────────────────────────
if (state !== previous) {
    const now        = Date.now();
    const durationMs = stateStart ? now - stateStart : 0;

    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:            "ACInput",
        site:             _config ? _config.site : "",
        timestamp:        new Date(now).toISOString(),
        source:           "AC_INPUT",
        event:            "AC_INPUT_STATE_CHANGED",
        previous_state:   label(previous),
        new_state:        label(state),
        duration_minutes: Math.round(durationMs / 60000),
        grid_lost_status: ""
    };

    saveState(state, now);

    msg.url = _appUrl;
    if (!_appUrl) { return null; }
    return msg;
}

return null;

let topic = msg.topic;
let value = Number(msg.payload);

const config = flow.get('config') || {};
const maxGapMinutes = config.maxIntegrationGapMinutes || 5;

const defaults = {
    lastTime: Date.now(),
    pv_kWh:0, grid_kWh:0, load_kWh:0,
    battery_charge_kWh:0, battery_discharge_kWh:0,
    pv_power:0, grid_l1:0, grid_l2:0, load_l1:0, load_l2:0,
    battery_power:0, ac_out_l1:0, ac_out_l2:0,
    min_soc:null, max_soc:null, soc_sum:0, soc_count:0,
    battery_voltage:null, battery_current:null, battery_temperature:null,
    min_voltage:null, max_voltage:null,
    min_temperature:null, max_temperature:null, temp_sum:0, temp_count:0,
    pv_yield_today_sc0:null, pv_yield_today_sc1:null,
    mppt_state_sc0:null, mppt_state_sc1:null,
    battery_reached_float: false,
    grid_frequency:null, grid_voltage_l1:null, grid_voltage_l2:null,
    min_grid_freq:null, max_grid_freq:null,
    min_grid_v_l1:null, max_grid_v_l1:null,
    min_grid_v_l2:null, max_grid_v_l2:null,
    vebus_state:null,
    sc0_t0_voltage:null, sc0_t0_power:null, sc0_t0_yield_today:null,
    sc0_t1_voltage:null, sc0_t1_power:null, sc0_t1_yield_today:null,
    sc0_t2_voltage:null, sc0_t2_power:null, sc0_t2_yield_today:null,
    sc0_t3_voltage:null, sc0_t3_power:null, sc0_t3_yield_today:null,
    sc1_t0_voltage:null, sc1_t0_power:null, sc1_t0_yield_today:null,
    sc1_t1_voltage:null, sc1_t1_power:null, sc1_t1_yield_today:null,
    sc1_t2_voltage:null, sc1_t2_power:null, sc1_t2_yield_today:null,
    sc1_t3_voltage:null, sc1_t3_power:null, sc1_t3_yield_today:null,
};

// Detect context wipe — stored energyData is missing or empty
const storedEd = flow.get('energyData');
const wasReset = !storedEd || storedEd.soc_count === undefined;

let data = Object.assign({}, defaults, storedEd || {});

let now = Date.now();
let dtHours = (now - data.lastTime) / 3600000;
if (dtHours < 0 || dtHours > (maxGapMinutes / 60)) dtHours = 0;

data.pv_kWh   += Math.max(0, data.pv_power) * dtHours / 1000;
data.grid_kWh += Math.max(0, (data.grid_l1||0) + (data.grid_l2||0)) * dtHours / 1000;
data.load_kWh += Math.max(0, (data.load_l1||0) + (data.load_l2||0)) * dtHours / 1000;
if (data.battery_power > 0) data.battery_charge_kWh    += data.battery_power * dtHours / 1000;
if (data.battery_power < 0) data.battery_discharge_kWh += Math.abs(data.battery_power) * dtHours / 1000;

data[topic] = value;

if (topic === "soc") {
    if (data.min_soc === null || value < data.min_soc) data.min_soc = value;
    if (data.max_soc === null || value > data.max_soc) data.max_soc = value;
    data.soc_sum += value; data.soc_count += 1;
}
if (topic === "battery_voltage") {
    if (data.min_voltage === null || value < data.min_voltage) data.min_voltage = value;
    if (data.max_voltage === null || value > data.max_voltage) data.max_voltage = value;
}
if (topic === "battery_temperature") {
    if (data.min_temperature === null || value < data.min_temperature) data.min_temperature = value;
    if (data.max_temperature === null || value > data.max_temperature) data.max_temperature = value;
    data.temp_sum += value; data.temp_count += 1;
}
if (topic === "vebus_state" && value === 5) {
    data.battery_reached_float = true;
}
if (topic === "grid_frequency" && value > 0) {
    if (data.min_grid_freq === null || value < data.min_grid_freq) data.min_grid_freq = value;
    if (data.max_grid_freq === null || value > data.max_grid_freq) data.max_grid_freq = value;
}
if (topic === "grid_voltage_l1" && value > 0) {
    if (data.min_grid_v_l1 === null || value < data.min_grid_v_l1) data.min_grid_v_l1 = value;
    if (data.max_grid_v_l1 === null || value > data.max_grid_v_l1) data.max_grid_v_l1 = value;
}
if (topic === "grid_voltage_l2" && value > 0) {
    if (data.min_grid_v_l2 === null || value < data.min_grid_v_l2) data.min_grid_v_l2 = value;
    if (data.max_grid_v_l2 === null || value > data.max_grid_v_l2) data.max_grid_v_l2 = value;
}

// ── Persist peak PV yield to flow context on every positive MPPT message ──
// MPPT resets Yield Today to 0 at sunset — this ensures lastPvYield always
// holds the true daily peak regardless of whether a manual inject ran
if (topic === "pv_yield_today_sc0" && value > 0) {
    const ly = flow.get('lastPvYield') || {};
    flow.set('lastPvYield', { sc0: value, sc1: ly.sc1 || null });
}
if (topic === "pv_yield_today_sc1" && value > 0) {
    const ly = flow.get('lastPvYield') || {};
    flow.set('lastPvYield', { sc0: ly.sc0 || null, sc1: value });
}

data.lastTime = now;
flow.set('energyData', data);

let avgSoc = data.soc_count > 0 ? data.soc_sum / data.soc_count : 0;
node.status({
    fill: "green", shape: "dot",
    text: "PV " + data.pv_kWh.toFixed(2) +
          " | Load " + data.load_kWh.toFixed(2) +
          " | SOC avg " + avgSoc.toFixed(1) +
          " | Batt " + (data.battery_voltage != null ? data.battery_voltage.toFixed(2) : "--") + "V" +
          " | F:" + (data.battery_reached_float?"1":"0") +
          " | L2:" + (data.min_grid_v_l2 != null ? data.min_grid_v_l2.toFixed(1) : "--")
});

// Output 1: normal (null — no downstream)
// Output 2: log to Supabase if context wipe detected
if (wasReset) {
    return [null, {
        logEvent: 'ACCUMULATOR_RESET',
        logLevel: 'warn',
        logData: {
            trigger_topic: topic,
            trigger_value: value,
            timestamp: new Date().toISOString()
        }
    }];
}
return [null, null];

const config = flow.get("config") || {};
const utcOffsetMs = (config.utcOffsetHours || -6) * 60 * 60 * 1000;

let ed = flow.get("energyData") || {};
let outage = flow.get("outageDaily") || { count:0, minutes:0 };

let now = new Date();
let localTime = new Date(now.getTime() + utcOffsetMs);
let summaryDate = localTime.toISOString().slice(0, 10);

let testing = msg.testing === true;

const avgSoc  = ed.soc_count  > 0 ? Number((ed.soc_sum  / ed.soc_count).toFixed(1))  : "";
const avgTemp = ed.temp_count > 0 ? Number((ed.temp_sum / ed.temp_count).toFixed(1)) : null;

// ── PV yield: use accumulator if positive, else fall back to lastPvYield
// MPPT resets Yield Today to 0 at sunset, before the 23:55 AUTO inject
const lastYield = flow.get('lastPvYield') || {};
const yieldSc0 = (ed.pv_yield_today_sc0 > 0) ? ed.pv_yield_today_sc0 : (lastYield.sc0 || null);
const yieldSc1 = (ed.pv_yield_today_sc1 > 0) ? ed.pv_yield_today_sc1 : (lastYield.sc1 || null);

msg.url     = config.appScriptUrl || '';
msg.headers = { "Content-Type": "application/json" };

msg.payload = {
    sheet: "DailySummary",
    site:  config.site || '',
    reportLanguage: config.reportLanguage || 'en',
    date:  summaryDate,

    // ── Energy (2dp) ─────────────────────────────────────────────
    pv_kWh:                Number((ed.pv_kWh                || 0).toFixed(2)),
    grid_kWh:              Number((ed.grid_kWh              || 0).toFixed(2)),
    load_kWh:              Number((ed.load_kWh              || 0).toFixed(2)),
    battery_charge_kWh:    Number((ed.battery_charge_kWh    || 0).toFixed(2)),
    battery_discharge_kWh: Number((ed.battery_discharge_kWh || 0).toFixed(2)),

    // ── SOC (1dp) ────────────────────────────────────────────────
    min_soc: ed.min_soc == null ? "" : Number(ed.min_soc.toFixed(1)),
    max_soc: ed.max_soc == null ? "" : Number(ed.max_soc.toFixed(1)),
    avg_soc: avgSoc,

    // ── Outages ──────────────────────────────────────────────────
    outage_count:   outage.count   || 0,
    outage_minutes: Number((outage.minutes || 0).toFixed(1)),

    // ── Battery health ───────────────────────────────────────────
    min_voltage:     ed.min_voltage     != null ? Number(ed.min_voltage.toFixed(2))     : null,
    max_voltage:     ed.max_voltage     != null ? Number(ed.max_voltage.toFixed(2))     : null,
    min_temperature: ed.min_temperature != null ? Number(ed.min_temperature.toFixed(1)) : null,
    max_temperature: ed.max_temperature != null ? Number(ed.max_temperature.toFixed(1)) : null,
    avg_temperature: avgTemp,

    // ── PV / MPPT ────────────────────────────────────────────────
    pv_yield_kwh_sc0:  yieldSc0 != null ? Number(yieldSc0.toFixed(3)) : null,
    pv_yield_kwh_sc1:  yieldSc1 != null ? Number(yieldSc1.toFixed(3)) : null,
    pv_yield_kwh_mppt: (yieldSc0 || 0) + (yieldSc1 || 0) > 0
                        ? Number(((yieldSc0 || 0) + (yieldSc1 || 0)).toFixed(3))
                        : null,
    battery_reached_float: ed.battery_reached_float || (ed.max_soc != null && ed.max_soc >= 100) || false,

    // ── Grid quality ─────────────────────────────────────────────
    min_grid_freq: ed.min_grid_freq != null ? Number(ed.min_grid_freq.toFixed(2)) : null,
    max_grid_freq: ed.max_grid_freq != null ? Number(ed.max_grid_freq.toFixed(2)) : null,
    min_grid_v_l1: ed.min_grid_v_l1 != null ? Number(ed.min_grid_v_l1.toFixed(1)) : null,
    max_grid_v_l1: ed.max_grid_v_l1 != null ? Number(ed.max_grid_v_l1.toFixed(1)) : null,
    min_grid_v_l2: ed.min_grid_v_l2 != null ? Number(ed.min_grid_v_l2.toFixed(1)) : null,
    max_grid_v_l2: ed.max_grid_v_l2 != null ? Number(ed.max_grid_v_l2.toFixed(1)) : null,

    // ── Grid data availability flag ───────────────────────────────
    grid_data_available: (ed.max_grid_v_l1 != null && ed.max_grid_v_l1 > 0),

    // ── Specs ────────────────────────────────────────────────────
    battery_usable_kwh: config.batteryUsableKWh || null,
    pv_kwp:             config.pvKwp            || null,
    health_thresholds:  config.healthThresholds  || null,
    latitude:           config.latitude          || null,
    longitude:          config.longitude         || null
};

if (testing) msg.payload.event = "TEST_DAILY_SUMMARY";

msg.livePowerSnapshot = {
    pv_power:           ed.pv_power      || 0,
    grid_l1:            ed.grid_l1       || 0,
    grid_l2:            ed.grid_l2       || 0,
    load_l1:            ed.load_l1       || 0,
    load_l2:            ed.load_l2       || 0,
    battery_power:      ed.battery_power || 0,
    ac_out_l1:          ed.ac_out_l1     || 0,
    ac_out_l2:          ed.ac_out_l2     || 0,
    pv_yield_today_sc0: yieldSc0,
    pv_yield_today_sc1: yieldSc1
};

msg.testing  = testing;
msg._isDailySummary = true;

// Persist peak yield — only overwrite if positive
// so post-sunset zero reset from MPPT does not erase the day's value
flow.set('lastPvYield', {
    sc0: (ed.pv_yield_today_sc0 > 0) ? ed.pv_yield_today_sc0 : (lastYield.sc0 || null),
    sc1: (ed.pv_yield_today_sc1 > 0) ? ed.pv_yield_today_sc1 : (lastYield.sc1 || null)
});

node.status({ fill:"blue", shape:"ring",
    text: "Prepared " + summaryDate + (testing ? " [TEST]" : "") });

return msg;

let alarmValue;

if (typeof msg.payload === "object") {
    if (msg.payload.value !== undefined) {
        alarmValue = Number(msg.payload.value);
    } else if (msg.payload.statusCode !== undefined) {
        alarmValue = Number(msg.payload.statusCode);
    } else {
        return null;
    }
} else {
    alarmValue = Number(msg.payload);
}

const config   = flow.get("config") || {};
const alarmKey = msg.topic || "unknown_alarm";

// ── State in flow context — survives re-deploys (node context does not) ─────
// All alarm baselines live under a single 'alarmState' object keyed by alarm type.
const alarmState = flow.get('alarmState') || {};
const previous   = alarmState[alarmKey]; // undefined on first boot / first deploy

function alarmNameFromTopic(topic) {
    if (topic === "low_battery")      return "Low Battery Alarm";
    if (topic === "high_temperature") return "High Temperature Alarm";
    if (topic === "overload")         return "Overload Alarm";
    if (topic === "charger_alarm")    return "Charger Alarm";
    if (topic === "vebus_error")      return "VE.Bus Error";
    if (topic === "battery_alarm")    return "Battery Alarm";
    return topic;
}

function statusLabel(v)   { return v === 0 ? "OK" : v === 1 ? "WARNING" : v === 2 ? "ALARM" : "UNKNOWN_" + v; }
function severityLabel(v) { return v === 0 ? "CLEARED" : v === 1 ? "WARNING" : v === 2 ? "ALARM" : "UNKNOWN"; }

const alarmName = alarmNameFromTopic(alarmKey);

node.status({
    fill:  alarmValue === 0 ? "green" : alarmValue === 1 ? "yellow" : "red",
    shape: "dot",
    text:  alarmName + ": " + statusLabel(alarmValue)
});

// Skip first reading — just record baseline, don't fire an event
if (previous === undefined) {
    alarmState[alarmKey] = alarmValue;
    flow.set('alarmState', alarmState);
    return null;
}

// Only fire on state change
if (alarmValue !== previous) {
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        sheet:     "AlarmEvents",
        site:      config.site   || "",
        timestamp: new Date().toISOString(),
        source:    alarmKey,
        alarm:     alarmName,
        status:    statusLabel(alarmValue),
        severity:  severityLabel(alarmValue)
    };
    alarmState[alarmKey] = alarmValue;
    flow.set('alarmState', alarmState);
    msg.url = config.appScriptUrl || "";
    return msg;
}

return null;

const config = {
    site:   "Vista Atenas LP M3",
    reportLanguage: "en",
    siteId: "vista-atenas-lp-m3",

    appScriptUrl: "https://script.google.com/macros/s/AKfycbww6PjJRTZ4gqrSA_CxS5eLBmN6QtUsEWzaT8kP2whv1i87vkG6u4TzqgW-xVstLYvUZw/exec",

    supabaseUrl:     env.get('SUPABASE_URL'),
    supabaseAnonKey: env.get('SUPABASE_ANON_KEY'),

    timezone: "America/Costa_Rica",
    utcOffsetHours: -6,

    dailySummaryLocalTime: "23:55",
    maxIntegrationGapMinutes: 30,

    mpptControllers: [
        { instance: 0, name: "MPPT 450/200 HQ2507WTYA7", trackers: [
            { index: 0, name: "S1", active: true }, { index: 1, name: "S2", active: true },
            { index: 2, name: "S3", active: true }, { index: 3, name: "N/A", active: false }
        ]},
        { instance: 1, name: "MPPT 450/200 HQ2507GFD9W", trackers: [
            { index: 0, name: "S4", active: true }, { index: 1, name: "S5", active: true },
            { index: 2, name: "S6", active: true }, { index: 3, name: "N/A", active: false }
        ]}
    ]

    // System specs (batteryUsableKWh, pvKwp, latitude, longitude) and
    // healthThresholds intentionally not set here — both come from
    // monitoring.sites via Merge Site Config. mpptControllers stays
    // local (hardware wiring, tied to physical input node selection).
};

flow.set("config", config);
node.status({ fill: "green", shape: "dot", text: "Config loaded: " + config.site });
node.log("Project config initialised for site: " + config.site);
return null;

const config     = flow.get('config') || {};
const testing    = msg.testing === true;
const statusCode = msg.statusCode || 0;
const body       = typeof msg.payload === 'string' ? msg.payload : JSON.stringify(msg.payload || '');
const success    = statusCode > 0;
const liveSnap   = msg.livePowerSnapshot || {};
const isManual   = msg._isManual === true;
const isDailySummary = msg._isDailySummary === true;

// Build log message for every HTTP response
const logMsg = {
    logEvent: 'HTTP_RESPONSE',
    logLevel: success ? 'info' : 'error',
    logData: {
        statusCode:    statusCode,
        testing:       testing,
        isManual:      isManual,
        isDailySummary: isDailySummary,
        willReset:     (success && !testing && !isManual && isDailySummary),
        timestamp:     new Date().toISOString()
    }
};

if (success && !testing && !isManual && isDailySummary) {
    flow.set('energyData', {
        lastTime: Date.now(),
        pv_kWh:0, grid_kWh:0, load_kWh:0,
        battery_charge_kWh:0, battery_discharge_kWh:0,
        pv_power:      liveSnap.pv_power      || 0,
        grid_l1:       liveSnap.grid_l1       || 0,
        grid_l2:       liveSnap.grid_l2       || 0,
        load_l1:       liveSnap.load_l1       || 0,
        load_l2:       liveSnap.load_l2       || 0,
        battery_power: liveSnap.battery_power || 0,
        ac_out_l1:     liveSnap.ac_out_l1     || 0,
        ac_out_l2:     liveSnap.ac_out_l2     || 0,
        min_soc:null, max_soc:null, soc_sum:0, soc_count:0,
        battery_voltage:null, battery_current:null, battery_temperature:null,
        min_voltage:null, max_voltage:null,
        min_temperature:null, max_temperature:null, temp_sum:0, temp_count:0,
        pv_yield_today_sc0: (flow.get('lastPvYield') || {}).sc0 || null,
        pv_yield_today_sc1: (flow.get('lastPvYield') || {}).sc1 || null,
        mppt_state_sc0:null, mppt_state_sc1:null,
        battery_reached_float: false,
        grid_frequency:null, grid_voltage_l1:null, grid_voltage_l2:null,
        min_grid_freq:null, max_grid_freq:null,
        min_grid_v_l1:null, max_grid_v_l1:null,
        min_grid_v_l2:null, max_grid_v_l2:null,
        vebus_state:null,
        sc0_t0_voltage:null, sc0_t0_power:null, sc0_t0_yield_today:null,
        sc0_t1_voltage:null, sc0_t1_power:null, sc0_t1_yield_today:null,
        sc0_t2_voltage:null, sc0_t2_power:null, sc0_t2_yield_today:null,
        sc0_t3_voltage:null, sc0_t3_power:null, sc0_t3_yield_today:null,
        sc1_t0_voltage:null, sc1_t0_power:null, sc1_t0_yield_today:null,
        sc1_t1_voltage:null, sc1_t1_power:null, sc1_t1_yield_today:null,
        sc1_t2_voltage:null, sc1_t2_power:null, sc1_t2_yield_today:null,
        sc1_t3_voltage:null, sc1_t3_power:null, sc1_t3_yield_today:null,
    });
    flow.set('outageDaily', { count:0, minutes:0 });
    node.status({ fill:'green', shape:'dot', text:'✓ Confirmed + counters reset' });
    node.log('Daily summary confirmed. Counters reset.');
} else if (success && !testing && isManual) {
    node.status({ fill:'blue', shape:'ring', text:'✓ Manual snapshot — no reset' });
} else if (success && !testing && !isManual && !isDailySummary) {
    node.status({ fill:'green', shape:'ring', text:'✓ Event posted — no reset' });
} else if (!success && !testing) {
    node.error('POST failed — no response received. Status: ' + statusCode);
    node.status({ fill:'red', shape:'dot', text:'✗ No response (connection failure)' });
} else if (testing) {
    node.status({ fill:'yellow', shape:'ring', text:'TEST — no reset' });
}

return logMsg;

const statusCode = msg.statusCode || 0;
const body       = typeof msg.payload === 'string' ? msg.payload : JSON.stringify(msg.payload || '');
const table      = msg._supaTable || 'unknown';

// Supabase returns 201 Created on successful INSERT with Prefer: return=minimal
if (statusCode === 201 || statusCode === 200) {
    node.status({ fill: 'green', shape: 'dot', text: '✓ ' + table + ' inserted' });
    node.log('Supabase INSERT ok: ' + table);
} else {
    node.error('Supabase INSERT failed [' + table + '] HTTP ' + statusCode + ': ' + body.slice(0, 200));
    node.status({ fill: 'red', shape: 'dot', text: '✗ ' + table + ' failed (' + statusCode + ')' });
}
return null;

