const config = flow.get('config') || {};
const ed     = flow.get('energyData') || {};
const ctrl   = config.mpptControllers || [];

const controllers = ctrl.map(c => {
    const trackers = c.trackers
        .filter(t => t.active)
        .map(t => {
            const prefix = 'sc' + c.instance + '_t' + t.index + '_';
            return {
                index:          t.index,
                name:           t.name,
                voltage_v:      ed[prefix + 'voltage']     || null,
                power_w:        ed[prefix + 'power']       || null,
                yield_today_kwh:ed[prefix + 'yield_today'] || null
            };
        });

    // Voltage spread — max minus min across active trackers
    const voltages = trackers
        .map(t => t.voltage_v)
        .filter(v => v !== null && v > 0);

    const voltageSpread = voltages.length > 1
        ? Number((Math.max(...voltages) - Math.min(...voltages)).toFixed(2))
        : null;

    return {
        instance:       c.instance,
        name:           c.name,
        charger_state:  ed['mppt_state_sc' + c.instance]    || null,
        pv_power_w:     ed['pv_power']                         || null,
        yield_today_kwh:ed['pv_yield_today_sc' + c.instance]   || null,
        voltage_spread: voltageSpread,
        trackers:       trackers
    };
});

msg.url     = config.supabaseUrl + '/mppt_snapshots';
msg.headers = {
