// ── Option 1: Write to Venus OS system log (readable via SSH) ────────────────
// journalctl -u node-red -f   OR   cat /var/log/node-red.log
const errorMsg  = (msg.error && msg.error.message) ? msg.error.message : String(msg.error || 'unknown error');
const errorNode = (msg.error && msg.error.source)  ? msg.error.source.name || msg.error.source.id : 'unknown node';
node.log('[FLOW ERROR] node="' + errorNode + '" error="' + errorMsg + '"');

// ── Option 2: Write to flow context for Daily Summary pickup ─────────────────
// Keeps a rolling log of the last 10 errors seen today.
// Cleared on successful daily reset alongside energyData.
const errors = flow.get('flowErrors') || [];
errors.push({
    time:    new Date().toISOString(),
    node:    errorNode,
    message: errorMsg
});

// Cap at 10 entries — oldest fall off
if (errors.length > 10) errors.splice(0, errors.length - 10);

flow.set('flowErrors', errors);

// Update node status so it's visible on the canvas
node.status({
    fill:  'red',
    shape: 'dot',
    text:  errorNode + ': ' + errorMsg.slice(0, 50)
});

return null;

