// Overlay DB config onto local fallback. Never wipes bootstrap keys
// (siteId / supabaseUrl / supabaseAnonKey aren't in the DB row).
function pick(dbVal, localVal) {
    return (dbVal === null || dbVal === undefined) ? localVal : dbVal;
}

const ok   = (msg.statusCode === undefined || msg.statusCode === 200);
const rows = msg.payload;

if (!ok || !Array.isArray(rows) || rows.length === 0) {
    node.warn('Site config fetch failed/empty — keeping local fallback config');
    node.status({ fill: 'yellow', shape: 'ring', text: 'Using local fallback config' });
    return null;
}

const site   = rows[0];
const config = flow.get('config') || {};

config.site             = pick(site.display_name,      config.site);
config.reportLanguage   = pick(site.report_language,   config.reportLanguage);
config.batteryUsableKWh = pick(site.battery_usable_kwh, config.batteryUsableKWh);
config.pvKwp            = pick(site.pv_kwp,             config.pvKwp);
config.latitude         = pick(site.latitude,          config.latitude);
config.longitude        = pick(site.longitude,         config.longitude);
config.timezone         = pick(site.timezone,          config.timezone);
config.utcOffsetHours   = pick(site.utc_offset_hours,  config.utcOffsetHours);
config.appScriptUrl     = pick(site.app_script_url,    config.appScriptUrl);
config.healthThresholds = Object.assign({}, config.healthThresholds, site.health_thresholds || {});

flow.set('config', config);
node.status({ fill: 'green', shape: 'dot', text: 'Config synced: ' + config.site });
node.log('Site config synced from Supabase for ' + config.siteId);
return null;
